const raw = $input.first().json;
const d = raw.body || raw;
const now = new Date();
const submitTime = now.toLocaleTimeString('zh-TW', { hour: '2-digit', minute: '2-digit', hour12: false });
const weekday = new Date(d.date + 'T00:00:00').toLocaleDateString('zh-TW', { weekday: 'long' });
const safeStr = s => (s || '').slice(0, 30);
const fileName = `${d.date}_${safeStr(d.contractor)}_${safeStr(d.projectName)}.pdf`;
const photoUrls = d.photoUrls || [];
return [{ json: { ...d, submitTime, weekday, fileName, photoUrls, photoCount: photoUrls.length } }];

const d = $input.first().json;
const lang = d.language || 'zh';
const LBL = {
  en: {
    title: 'Work Daily Report',
    projectName: 'Project Name', constructionArea: 'Construction Area',
    date: 'Date', weekday: 'Day',
    weather: 'Weather', morning: 'AM', afternoon: 'PM',
    time: 'Submit Time',
    constructionLocation: 'Construction Location',
    workContent: 'Work Content',
    constructionItems: 'Construction Items (Today)',
    tomorrowPlan: "Tomorrow's Plan",
    materialsUsed: 'Materials Used', equipment: 'Equipment Used',
    workers: 'Workers', persons: '',
    communication: 'Contractor Communication',
    otherNotes: 'Other Notes',
    samplingTests: 'Sampling & Testing Records',
    qualityInspection: 'Quality & Qty Inspection',
    supervisor: 'Unit Supervisor', inspector: 'Inspector'
  },
  th: {
    title: 'บันทึกงานประจำวัน',
    projectName: 'ชื่อโครงการ', constructionArea: 'พื้นที่ก่อสร้าง',
    date: 'วันที่', weekday: 'วัน',
    weather: 'สภาพอากาศ', morning: 'เช้า', afternoon: 'บ่าย',
    time: 'เวลาที่ส่ง',
    constructionLocation: 'ตำแหน่งก่อสร้าง',
    workContent: 'เนื้อหางาน',
    constructionItems: 'รายการงาน (วันนี้)',
    tomorrowPlan: 'แผนงานพรุ่งนี้',
    materialsUsed: 'วัสดุที่ใช้', equipment: 'เครื่องมือ',
    workers: 'จำนวนคน', persons: 'คน',
    communication: 'การสื่อสารกับผู้รับเหมา',
    otherNotes: 'หมายเหตุสำคัญ',
    samplingTests: 'การเก็บตัวอย่าง',
    qualityInspection: 'การตรวจสอบคุณภาพ',
    supervisor: 'ผู้จัดการ', inspector: 'ผู้ตรวจสอบ'
  },
  zh: {
    title: '監工人員工作日誌',
    projectName: '工程名稱', constructionArea: '施工廠區',
    date: '日期', weekday: '星期',
    weather: '天氣', morning: '上午', afternoon: '下午',
    time: '時間',
    constructionLocation: '施工部位',
    workContent: '工作內容',
    constructionItems: '施工項目（今日）',
    tomorrowPlan: '明日預計工作',
    materialsUsed: '供給材料使用', equipment: '機具使用',
    workers: '出工人數', persons: '人',
    communication: '與廠商溝通協調記錄',
    otherNotes: '其他重要事項記錄',
    samplingTests: '施工取樣試驗記錄',
    qualityInspection: '品質、數量檢查記錄',
    supervisor: '單位主管', inspector: '監工人員'
  }
};
const L = LBL[lang] || LBL.zh;
const LZH = LBL.zh;
const photoUrls = d.photoUrls || [];
const esc = s => String(s || '-').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
let photoHtml = '';
if (photoUrls.length > 0) {
  for (let i = 0; i < photoUrls.length; i += 4) {
    const chunk = photoUrls.slice(i, i + 4);
    const cells = chunk.map(url => `<td style='width:50%;padding:4px'><img src='${url}' style='width:100%;height:auto'></td>`);
    while (cells.length < 4) cells.push(`<td style='width:50%;padding:4px'></td>`);
    photoHtml += `<table style='width:100%;border-collapse:collapse;margin-top:8px;page-break-inside:avoid'><tr>${cells.slice(0,2).join('')}</tr><tr>${cells.slice(2,4).join('')}</tr></table>`;
  }
}
function buildHtml(Lb) {
  return `<!DOCTYPE html><html><head><meta charset='UTF-8'><style>body{font-family:Arial,'Noto Sans Thai',sans-serif;font-size:10pt;margin:0}.t{text-align:center;font-weight:bold;margin-bottom:4px}table.m{width:100%;border-collapse:collapse}table.m td{border:1px solid #333;padding:4px 6px;vertical-align:top}.sh{background:#ddd;font-weight:bold;text-align:center}.c{min-height:40px;white-space:pre-wrap}</style></head><body><div class='t' style='font-size:14pt'>ECO INFINIC</div><div class='t' style='font-size:12pt;margin-bottom:8px'>${Lb.title}</div><table class='m'><tr><td style='width:12%'><b>${Lb.projectName}</b></td><td style='width:38%'>${esc(d.projectName)}</td><td style='width:12%'><b>${Lb.constructionArea}</b></td><td style='width:38%'>${esc(d.constructionArea)}</td></tr><tr><td><b>${Lb.date}</b></td><td>${esc(d.date)}</td><td><b>${Lb.weekday}</b></td><td>${esc(d.weekday)}</td></tr><tr><td><b>${Lb.weather}</b></td><td colspan='3'>${Lb.morning}: ${esc(d.morningWeather)} / ${Lb.afternoon}: ${esc(d.afternoonWeather)}</td></tr><tr><td><b>${Lb.time}</b></td><td colspan='3'>${esc(d.submitTime)}</td></tr><tr><td class='sh' colspan='4'>${Lb.constructionLocation}</td></tr><tr><td colspan='4' class='c'>${esc(d.constructionLocation)}</td></tr><tr><td class='sh' colspan='4'>${Lb.workContent}</td></tr><tr><td><b>${Lb.constructionItems}</b></td><td colspan='3' class='c' style='min-height:60px'>${esc(d.constructionItems)}</td></tr><tr><td><b>${Lb.tomorrowPlan}</b></td><td colspan='3' class='c' style='min-height:50px'>${esc(d.tomorrowPlan)}</td></tr><tr><td><b>${Lb.materialsUsed}</b></td><td>${esc(d.materialsUsed)}</td><td><b>${Lb.equipment}</b></td><td>${esc(d.equipment)}</td></tr><tr><td><b>${Lb.workers}</b></td><td colspan='3'>${esc(d.workers)} ${Lb.persons}</td></tr><tr><td class='sh' colspan='4'>${Lb.communication}</td></tr><tr><td colspan='4' class='c'>${esc(d.communication)}</td></tr><tr><td class='sh' colspan='4'>${Lb.otherNotes}</td></tr><tr><td colspan='4' class='c'>${esc(d.otherNotes)}</td></tr><tr><td colspan='2'><b>${Lb.samplingTests}</b></td><td colspan='2'><b>${Lb.qualityInspection}</b></td></tr><tr><td colspan='2' class='c'>${esc(d.samplingTests)}</td><td colspan='2' class='c'>${esc(d.qualityInspection)}</td></tr><tr><td><b>${Lb.supervisor}</b></td><td></td><td><b>${Lb.inspector}</b></td><td>${esc(d.supervisor)}</td></tr></table>${photoHtml}</body></html>`;
}
const html = buildHtml(L);
const htmlZH = buildHtml(LZH);
return [{ json: { ...d, pdfHtml: html, pdfHtmlZH: htmlZH } }];

const prepData = $('Prepare Data').first().json;
const driveFileId = $('Google Drive Upload').first().json.id;
const driveUrl = 'https://drive.google.com/file/d/' + driveFileId + '/view';
const driveFileIdZH = $('Google Drive Upload (ZH)').first().json.id;
const driveUrlZH = 'https://drive.google.com/file/d/' + driveFileIdZH + '/view';
const lang = prepData.language || 'en';
const CL = {
  en: { title: 'Work Report Ready', date: 'Date', project: 'Project', photos: 'Photos', download: 'Download PDF Report' },
  th: { title: 'รายงานงานพร้อมแล้ว', date: 'วันที่', project: 'โครงการ', photos: 'รูปภาพ', download: 'ดาวน์โหลดรายงาน PDF' },
  zh: { title: '工作日誌已生成', date: '日期', project: '工程', photos: '照片', download: '下載 PDF 報告' }
}[lang] || { title: 'Work Report Ready', date: 'Date', project: 'Project', photos: 'Photos', download: 'Download PDF Report' };
const contractorFlex = { to: prepData.lineUserId, messages: [{ type: 'flex', altText: CL.title, contents: { type: 'bubble', header: { type: 'box', layout: 'vertical', backgroundColor: '#1a73e8', contents: [{ type: 'text', text: CL.title, color: '#ffffff', weight: 'bold', size: 'lg' }] }, body: { type: 'box', layout: 'vertical', spacing: 'sm', contents: [{ type: 'text', text: CL.date + ': ' + prepData.date, size: 'sm', color: '#555555' }, { type: 'text', text: CL.project + ': ' + prepData.projectName, size: 'sm', color: '#555555' }, { type: 'text', text: CL.photos + ': ' + prepData.photoCount, size: 'sm', color: '#555555' }] }, footer: { type: 'box', layout: 'vertical', contents: [{ type: 'button', style: 'primary', color: '#1a73e8', action: { type: 'uri', label: CL.download, uri: driveUrl } }] } } }] };
const jerryFlex = { to: 'Ubf65144da2093a2cb9e01528d773413f', messages: [{ type: 'flex', altText: '監工日誌報告已生成', contents: { type: 'bubble', header: { type: 'box', layout: 'vertical', backgroundColor: '#0d7a0d', contents: [{ type: 'text', text: '監工日誌報告已生成', color: '#ffffff', weight: 'bold', size: 'lg' }] }, body: { type: 'box', layout: 'vertical', spacing: 'sm', contents: [{ type: 'text', text: '日期: ' + prepData.date, size: 'sm', color: '#555555' }, { type: 'text', text: '工程: ' + prepData.projectName, size: 'sm', color: '#555555' }, { type: 'text', text: '廠商: ' + prepData.contractor, size: 'sm', color: '#555555' }, { type: 'text', text: '照片: ' + prepData.photoCount + ' 張', size: 'sm', color: '#555555' }] }, footer: { type: 'box', layout: 'vertical', contents: [{ type: 'button', style: 'primary', color: '#0d7a0d', action: { type: 'uri', label: '下載中文 PDF 報告', uri: driveUrlZH } }] } } }] };
return [{ json: { contractorPayload: JSON.stringify(contractorFlex), jerryPayload: JSON.stringify(jerryFlex) } }];
